SELECT rp.role_id as roleId, rp.permission_id as permissionId FROM sys_role_permission rp INNER JOIN sys_permission p ON rp.permission_id = p.id WHERE rp.role_id IN
#{roleId}
AND p.status = 1 AND p.deleted = 0

SELECT rm.role_id as roleId, rm.menu_id as menuId FROM sys_role_menu rm INNER JOIN sys_menu m ON rm.menu_id = m.id WHERE rm.role_id IN
#{roleId}
AND m.status = 1 AND m.deleted = 0
